import { GoogleGenAI, Type } from "@google/genai";

// Acesso seguro à chave de API
const apiKey = process.env.API_KEY || "";

// Inicialização condicional
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

/**
 * MOCK DATA: Dados de contingência para quando a API estiver indisponível
 * Garante que a "Fundação" do app nunca quebre.
 */
const MOCK_SCREENING = {
  economy: "Comércio lindeiro em alta devido à temporada de festas juninas aproximando-se. Setor de serviços (oficinas e postos) com demanda 15% acima da média.",
  events: "Feira de Caruaru operando com fluxo máximo. Gravatá com eventos gastronômicos no fim de semana.",
  pulse: "Vibração alta. Motoristas relatando fluxo intenso mas fluido. Sensação de segurança reforçada no trecho da Serra.",
  opportunities: "Alta demanda por fretes refrigerados saindo do Polo de Logística. Vagas para mecânicos diesel em Bezerros."
};

const MOCK_ROAD_NEWS = {
  summary: "Monitoramento Ativo: Fluxo intenso na altura da Serra das Russas, mas sem retenções graves. Atenção para neblina noturna.",
  sources: [
    { title: "Boletim PRF - BR232", uri: "#" },
    { title: "Clima Tempo - Agreste", uri: "#" }
  ]
};

const MOCK_ROAD_STATUS = {
  status: "Fluxo Moderado",
  color: "#eab308", // Yellow warning
  advice: "Reduza na descida da Serra. Pista úmida."
};

const MOCK_ETHICS_SCORE = 0.85;

/**
 * Motor de Screening: Analisa a 'Vida' de uma cidade específica na malha.
 */
export const performCommunityScreening = async (cityName: string): Promise<any> => {
  // Se não houver IA configurada ou erro, retorna Mock da Fundação
  if (!ai) return { ...MOCK_SCREENING, economy: `Análise local de ${cityName}: ${MOCK_SCREENING.economy}` };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Faça um 'Screening' da cidade de ${cityName}, Pernambuco, na BR-232. 
      Analise: Economia local, Eventos e Pulse (humor da cidade).
      Responda estritamente em JSON.`,
      config: { 
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            economy: { type: Type.STRING },
            events: { type: Type.STRING },
            pulse: { type: Type.STRING },
            opportunities: { type: Type.STRING }
          },
          required: ["economy", "events", "pulse", "opportunities"]
        }
      },
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.warn("Gemini API indisponível, usando dados da Fundação:", error);
    return { ...MOCK_SCREENING, economy: `(Dados em Cache) ${cityName}: ${MOCK_SCREENING.economy}` };
  }
};

/**
 * Agente de Hermenêutica: Analisa feedbacks para medir discrição e ética.
 */
export const analyzePilotFeedback = async (feedbacks: string[]): Promise<number> => {
  if (!ai) return MOCK_ETHICS_SCORE;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analise a ética destes feedbacks de pilotos na BR-232: "${feedbacks.join(' | ')}".
      Retorne APENAS um número de 0 a 1 para o 'Fator Discrição'.`,
    });
    const text = response.text || "0.5";
    const score = parseFloat(text.trim());
    return isNaN(score) ? 0.5 : score;
  } catch (error) {
    return MOCK_ETHICS_SCORE;
  }
};

/**
 * Busca notícias REAIS focadas exclusivamente na BR-232.
 */
export const getRealTimeRoadNews = async (): Promise<{ summary: string; sources: { title: string; uri: string }[] }> => {
  if (!ai) return MOCK_ROAD_NEWS;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `O que está acontecendo agora na rodovia BR-232 em Pernambuco? Foque em alertas reais.`,
      config: { tools: [{ googleSearch: {} }] },
    });
    const summary = response.text || "Fluxo normal na Luiz Gonzaga.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = chunks.filter((chunk: any) => chunk.web).map((chunk: any) => ({
      title: chunk.web.title,
      uri: chunk.web.uri
    }));
    return { summary, sources };
  } catch (error) {
    return MOCK_ROAD_NEWS;
  }
};

/**
 * Analisa o status da rodovia baseado nos alertas locais.
 */
export const analyzeRoadStatus = async (alerts: any[]): Promise<{ status: string; color: string; advice: string }> => {
  if (!ai) return MOCK_ROAD_STATUS;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analise estes incidentes: ${JSON.stringify(alerts)}. Retorne JSON com status, color (HEX) e advice regional.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            color: { type: Type.STRING },
            advice: { type: Type.STRING }
          },
          required: ["status", "color", "advice"]
        }
      }
    });
    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    return MOCK_ROAD_STATUS;
  }
};

