const Login: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleGoogleLogin = async () => {
    setIsLoading(true);
    setErrorMsg(null);

    // Verifica mock/segurança
    if (!auth.app && !auth.currentUser) {
       // Fallback para ambiente sem Firebase configurado (Desenvolvimento UI)
       console.warn("Modo Fundação: Simulando Login Google");
       setTimeout(() => {
         onLogin();
         navigate('/verificar'); // Redireciona para Validação
       }, 1500);
       return;
    }

    try {
      const result = await signInWithPopup(auth, googleProvider);
      const user = result.user;
      console.log("Acesso autorizado:", user.email);
      onLogin(); 
      navigate('/verificar'); // Redireciona para Validação

    } catch (error: any) {
      console.error("Erro no login:", error);
      if (error.code === 'auth/popup-closed-by-user') {
        setErrorMsg("Acesso cancelado pelo usuário.");
      } else if (error.code === 'auth/invalid-api-key') {
        // Fallback gracioso se a chave for inválida no ambiente de teste
        onLogin();
        navigate('/verificar');
      } else {
        setErrorMsg("Falha na conexão segura com Google. Tente novamente.");
