  const [code, setCode] = useState('');
  const [timer, setTimer] = useState(30);

  useEffect(() => {
    let interval: any;
    if (status === 'sent' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [status, timer]);

  const handleSendCode = () => {
    setStatus('sending');
    // MOCK: Simula tempo de rede e "envia" o código
    setTimeout(() => {
      setStatus('sent');
      setTimer(30);
    }, 1500);
  };

  const handleVerify = () => {
    // MOCK: Aceita qualquer código de 6 dígitos para facilitar testes
    if (code.length === 6) {
      setStatus('verifying');
      setTimeout(() => {
        setStatus('success');
        setTimeout(() => {
          navigate('/dashboard');
        }, 1500);
      }, 2000);
