export default Verify;

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';

// Pages
import Welcome from './pages/Welcome';
import Login from './pages/Login';
import Home from './pages/Home';
import Alerts from './pages/Alerts';
import Classifieds from './pages/Classifieds';
import CommunityLife from './pages/CommunityLife';
import Blog from './pages/Blog';
import Patrons from './pages/Patrons';
import ReportAlert from './pages/ReportAlert';
import MotoTaxi from './pages/MotoTaxi';
import PostAd from './pages/PostAd';
import Roadmap from './pages/Roadmap';
import Profile from './pages/Profile';
import AdminDashboard from './pages/AdminDashboard';
import Terms from './pages/Terms';
import Manifesto from './pages/Manifesto';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('ecobr232_auth') === 'true';
  });

  const login = () => {
    localStorage.setItem('ecobr232_auth', 'true');
    setIsAuthenticated(true);
  };

  const logout = () => {
    localStorage.removeItem('ecobr232_auth');
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="min-h-screen bg-[#050d09] text-white font-display selection:bg-primary selection:text-black">
        <SafetyGuard />
        <Layout auth={isAuthenticated}>
          <Routes>
            {/* Rotas Públicas (Leitura e Navegação) */}
            <Route path="/" element={<Welcome />} />
            <Route path="/login" element={<Login onLogin={login} />} />
            <Route path="/termos" element={<Terms />} />
            <Route path="/manifesto" element={<Manifesto />} />
            <Route path="/dashboard" element={<Home auth={isAuthenticated} />} />
            <Route path="/alertas" element={<Alerts />} />
            <Route path="/classificados" element={<Classifieds />} />
            <Route path="/vida" element={<CommunityLife auth={isAuthenticated} />} />
            <Route path="/blog" element={<Blog />} />
            <Route path="/patronos" element={<Patrons />} />
            <Route path="/roadmap" element={<Roadmap />} />
            <Route path="/moto-taxi" element={<MotoTaxi />} />

            {/* Rotas Protegidas (Escrita e Dados Pessoais) */}
            <Route 
              path="/perfil" 
              element={isAuthenticated ? <Profile onLogout={logout} /> : <Navigate to="/login" replace />} 
            />
            <Route 
              path="/reportar" 
              element={isAuthenticated ? <ReportAlert /> : <Navigate to="/login" replace />} 
            />
            <Route 
              path="/anunciar" 
              element={isAuthenticated ? <PostAd /> : <Navigate to="/login" replace />} 
            />

            {/* Rota Administrativa (Proteção Crítica) */}
            <Route 
              path="/admin" 
              element={isAuthenticated ? <AdminDashboard /> : <Navigate to="/login" replace />} 
            />
          </Routes>
        </Layout>
      </div>
    </Router>
  );
};

const SafetyGuard: React.FC = () => {
  const [speedAlert, setSpeedAlert] = useState(false);
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => { if ((pos.coords.speed || 0) > 15) setSpeedAlert(true); else setSpeedAlert(false); },
      () => {}, { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);
  if (!speedAlert) return null;
  return (
    <div className="fixed inset-0 z-[10000] bg-red-600 flex flex-col items-center justify-center p-8 text-center">
      <span className="material-symbols-outlined text-[120px] text-white mb-6 filled">front_hand</span>
      <h2 className="text-white text-3xl font-black mb-4 italic uppercase">Vixe! Tá correndo é?</h2>
      <p className="text-white/90 text-lg font-bold mb-8">Pare o carro num lugar seguro pra usar o app!</p>
      <button onClick={() => setSpeedAlert(false)} className="px-8 py-4 bg-white text-red-600 rounded-2xl font-black uppercase shadow-2xl">Já parei!</button>
    </div>
  );
};

const Layout: React.FC<{ children: React.ReactNode, auth: boolean }> = ({ children, auth }) => {
  return (
    <div className="flex flex-col min-h-screen relative">
      <main className="flex-1 overflow-x-hidden">
        {children}
      </main>
      <BottomNav auth={auth} />
    </div>
  );
};

const BottomNav: React.FC<{ auth: boolean }> = ({ auth }) => {
  const location = useLocation();

  // Esconde a barra de navegação em telas de foco total ou formulários
  if (['/reportar', '/anunciar', '/login', '/', '/termos', '/manifesto'].includes(location.pathname)) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 z-[100] pb-[env(safe-area-inset-bottom)] bg-[#050d09] border-t border-white/5">
      <nav className="h-18 px-8 flex items-center justify-between max-w-lg mx-auto">
        <NavItem to="/dashboard" icon="home" label="Início" active={location.pathname === '/dashboard'} />
        <NavItem to="/alertas" icon="map" label="Mapa" active={location.pathname === '/alertas'} />
        <NavItem to="/vida" icon="explore" label="Explorar" active={location.pathname === '/vida'} />
        <NavItem 
          to={auth ? "/perfil" : "/login"} 
          icon={auth ? "account_circle" : "person"} 
          label={auth ? "Perfil" : "Entrar"} 
          active={location.pathname === '/perfil' || location.pathname === '/login'} 
        />
      </nav>
    </div>
  );
};

const NavItem: React.FC<{ to: string; icon: string; label: string; active: boolean }> = ({ to, icon, label, active }) => (
  <Link to={to} className={`flex flex-col items-center justify-center gap-1 transition-all duration-300 ${active ? 'text-primary' : 'text-slate-500'}`}>
    <span className={`material-symbols-outlined text-[24px] ${active ? 'filled' : ''}`}>
      {icon}
    </span>
    <span className="text-[9px] font-black uppercase tracking-tight">
      {label}
    </span>
  </Link>
);

export default App;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Loader2, AlertCircle, ShieldCheck, Zap, Database } from 'lucide-react';
import { signInWithPopup } from 'firebase/auth';
import { auth, googleProvider } from '../services/firebase';
import Logo from '../components/Logo';

const Login: React.FC<{ onLogin: () => void }> = ({ onLogin }) => {
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleGoogleLogin = async () => {
    setIsLoading(true);
    setErrorMsg(null);

    // Verifica mock/segurança
    if (!auth.app && !auth.currentUser) {
       // Fallback para ambiente sem Firebase configurado (Desenvolvimento UI)
       console.warn("Modo Fundação: Simulando Login Google");
       setTimeout(() => {
         onLogin();
         navigate('/dashboard'); // Acesso direto
       }, 1500);
       return;
    }

    try {
      const result = await signInWithPopup(auth, googleProvider);
      const user = result.user;
      console.log("Acesso autorizado:", user.email);
      onLogin(); 
      navigate('/dashboard'); // Acesso direto, Google garante a identidade

    } catch (error: any) {
      console.error("Erro no login:", error);
      if (error.code === 'auth/popup-closed-by-user') {
        setErrorMsg("Acesso cancelado pelo usuário.");
      } else if (error.code === 'auth/invalid-api-key') {
        // Fallback gracioso se a chave for inválida no ambiente de teste
        onLogin();
        navigate('/dashboard');
      } else {
        setErrorMsg("Falha na conexão segura com Google. Tente novamente.");
      }
    } finally {
      setIsLoading(false); // Mantém loading se redirecionar, mas aqui limpamos caso de erro
    }
  };

  return (
    <div className="bg-background-dark min-h-screen text-white font-display flex flex-col relative overflow-hidden">

      {/* Background Ambient Effects */}
      <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-primary/10 to-transparent pointer-events-none"></div>
