import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RotateCcw, Home } from 'lucide-react';

interface Props {
  children?: ReactNode;
  moduleName?: string;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * Módulo de Segurança (Shielding)
 * Impede que falhas em sub-módulos derrubem a aplicação inteira.
 */
class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`[CRITICAL] Falha no módulo ${this.props.moduleName}:`, error, errorInfo);
    // Aqui poderíamos enviar para um serviço de log como Sentry/Firebase Crashlytics
  }

  public handleRetry = () => {
    this.setState({ hasError: false, error: null });
    window.location.reload();
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] p-8 text-center bg-background-dark/50 rounded-[2rem] border border-red-500/20 m-4">
          <div className="size-16 bg-red-500/10 rounded-2xl flex items-center justify-center mb-6 border border-red-500/20 animate-pulse">
            <AlertTriangle size={32} className="text-red-500" />
          </div>

          <h2 className="text-xl font-black italic uppercase text-white mb-2">
            Módulo Indisponível
          </h2>

          <p className="text-sm text-slate-400 font-medium max-w-xs mx-auto mb-8 leading-relaxed">
            Ocorreu uma instabilidade na área <span className="text-primary font-bold">{this.props.moduleName || 'Sistema'}</span>. 
            A operação foi isolada para proteger o restante da malha.
          </p>

          <div className="flex gap-4">
            <button 
              onClick={() => window.location.href = '#/dashboard'}
              className="px-6 py-3 bg-white/5 rounded-xl text-xs font-black uppercase text-white border border-white/10 hover:bg-white/10 flex items-center gap-2"
            >
              <Home size={14} /> Início
            </button>
            <button 
              onClick={this.handleRetry}
              className="px-6 py-3 bg-primary text-black rounded-xl text-xs font-black uppercase border border-primary hover:brightness-110 flex items-center gap-2"
            >
              <RotateCcw size={14} /> Reconectar
            </button>
          </div>

          <div className="mt-8 pt-8 border-t border-white/5 w-full">
            <p className="text-[9px] font-mono text-slate-600 uppercase">
              ERR_CODE: {this.state.error?.name || 'UNKNOWN'}
            </p>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import React, { useState, useEffect, Suspense } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { Loader2 } from 'lucide-react';

// Componente de Blindagem
import ErrorBoundary from './components/ErrorBoundary';

// Lazy Loading Modules (Code Splitting)
// Isso garante que cada módulo seja um "bundle" separado.
const Welcome = React.lazy(() => import('./pages/Welcome'));
const Login = React.lazy(() => import('./pages/Login'));
const Home = React.lazy(() => import('./pages/Home'));
const Alerts = React.lazy(() => import('./pages/Alerts'));
const Classifieds = React.lazy(() => import('./pages/Classifieds'));
const CommunityLife = React.lazy(() => import('./pages/CommunityLife'));
const Blog = React.lazy(() => import('./pages/Blog'));
const Patrons = React.lazy(() => import('./pages/Patrons'));
const ReportAlert = React.lazy(() => import('./pages/ReportAlert'));
const MotoTaxi = React.lazy(() => import('./pages/MotoTaxi'));
const PostAd = React.lazy(() => import('./pages/PostAd'));
const Roadmap = React.lazy(() => import('./pages/Roadmap'));
const Profile = React.lazy(() => import('./pages/Profile'));
const AdminDashboard = React.lazy(() => import('./pages/AdminDashboard'));
const Terms = React.lazy(() => import('./pages/Terms'));
const Manifesto = React.lazy(() => import('./pages/Manifesto'));

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('ecobr232_auth') === 'true';
  });

  const login = () => {
    localStorage.setItem('ecobr232_auth', 'true');
    setIsAuthenticated(true);
  };

  const logout = () => {
    localStorage.removeItem('ecobr232_auth');
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="min-h-screen bg-[#050d09] text-white font-display selection:bg-primary selection:text-black">
        <SafetyGuard />
        <Layout auth={isAuthenticated}>
          <Suspense fallback={<LoadingScreen />}>
            <Routes>
              {/* Rotas Públicas (Leitura e Navegação) */}
              <Route path="/" element={<Welcome />} />
              <Route path="/login" element={<ErrorBoundary moduleName="Autenticação"><Login onLogin={login} /></ErrorBoundary>} />
              <Route path="/termos" element={<Terms />} />
              <Route path="/manifesto" element={<Manifesto />} />

              {/* Módulos Core - Protegidos individualmente */}
              <Route path="/dashboard" element={
                <ErrorBoundary moduleName="Dashboard Principal">
                  <Home auth={isAuthenticated} />
                </ErrorBoundary>
              } />

              <Route path="/alertas" element={
                <ErrorBoundary moduleName="Monitoramento">
                  <Alerts />
                </ErrorBoundary>
              } />

              <Route path="/classificados" element={
                <ErrorBoundary moduleName="Marketplace">
                  <Classifieds />
                </ErrorBoundary>
              } />

              <Route path="/vida" element={
                <ErrorBoundary moduleName="Vida Comunitária">
                  <CommunityLife auth={isAuthenticated} />
                </ErrorBoundary>
              } />

              <Route path="/blog" element={<ErrorBoundary moduleName="Notícias"><Blog /></ErrorBoundary>} />
              <Route path="/patronos" element={<ErrorBoundary moduleName="Parceiros"><Patrons /></ErrorBoundary>} />
              <Route path="/roadmap" element={<Roadmap />} />

              {/* Módulo Especializado: Moto-Táxi */}
              <Route path="/moto-taxi" element={
                <ErrorBoundary moduleName="Ranking Moto-Táxi">
                  <MotoTaxi />
                </ErrorBoundary>
              } />

              {/* Rotas Protegidas (Escrita e Dados Pessoais) */}
              <Route 
                path="/perfil" 
                element={isAuthenticated ? <ErrorBoundary moduleName="Perfil do Usuário"><Profile onLogout={logout} /></ErrorBoundary> : <Navigate to="/login" replace />} 
              />
              <Route 
                path="/reportar" 
                element={isAuthenticated ? <ErrorBoundary moduleName="Reporte de Alertas"><ReportAlert /></ErrorBoundary> : <Navigate to="/login" replace />} 
              />
              <Route 
                path="/anunciar" 
                element={isAuthenticated ? <ErrorBoundary moduleName="Gestor de Anúncios"><PostAd /></ErrorBoundary> : <Navigate to="/login" replace />} 
              />

              {/* Rota Administrativa (Proteção Crítica) */}
              <Route 
                path="/admin" 
                element={isAuthenticated ? <ErrorBoundary moduleName="Admin Dashboard"><AdminDashboard /></ErrorBoundary> : <Navigate to="/login" replace />} 
              />
            </Routes>
          </Suspense>
        </Layout>
      </div>
    </Router>
  );
};

const LoadingScreen = () => (
  <div className="flex flex-col items-center justify-center min-h-[60vh] text-primary space-y-4">
    <Loader2 size={40} className="animate-spin" />
    <p className="text-[10px] font-black uppercase tracking-[0.3em] animate-pulse">Carregando Módulo...</p>
  </div>
);

const SafetyGuard: React.FC = () => {
  const [speedAlert, setSpeedAlert] = useState(false);
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => { if ((pos.coords.speed || 0) > 15) setSpeedAlert(true); else setSpeedAlert(false); },
      () => {}, { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);
  if (!speedAlert) return null;
  return (
    <div className="fixed inset-0 z-[10000] bg-red-600 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-300">
      <span className="material-symbols-outlined text-[120px] text-white mb-6 filled">front_hand</span>
      <h2 className="text-white text-3xl font-black mb-4 italic uppercase">Vixe! Tá correndo é?</h2>
      <p className="text-white/90 text-lg font-bold mb-8">Pare o carro num lugar seguro pra usar o app!</p>
      <button onClick={() => setSpeedAlert(false)} className="px-8 py-4 bg-white text-red-600 rounded-2xl font-black uppercase shadow-2xl active:scale-95 transition-transform">Já parei!</button>
    </div>
  );
};

const Layout: React.FC<{ children: React.ReactNode, auth: boolean }> = ({ children, auth }) => {
  return (
    <div className="flex flex-col min-h-screen relative">
      <main className="flex-1 overflow-x-hidden">
        {children}
      </main>
      <BottomNav auth={auth} />
    </div>
  );
};

const BottomNav: React.FC<{ auth: boolean }> = ({ auth }) => {
  const location = useLocation();

  // Esconde a barra de navegação em telas de foco total ou formulários
  if (['/reportar', '/anunciar', '/login', '/', '/termos', '/manifesto'].includes(location.pathname)) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 z-[100] pb-[env(safe-area-inset-bottom)] bg-[#050d09] border-t border-white/5">
      <nav className="h-18 px-8 flex items-center justify-between max-w-lg mx-auto">
        <NavItem to="/dashboard" icon="home" label="Início" active={location.pathname === '/dashboard'} />
        <NavItem to="/alertas" icon="map" label="Mapa" active={location.pathname === '/alertas'} />
        <NavItem to="/vida" icon="explore" label="Explorar" active={location.pathname === '/vida'} />
        <NavItem 
          to={auth ? "/perfil" : "/login"} 
          icon={auth ? "account_circle" : "person"} 
          label={auth ? "Perfil" : "Entrar"} 
          active={location.pathname === '/perfil' || location.pathname === '/login'} 
        />
      </nav>
    </div>
  );
};

const NavItem: React.FC<{ to: string; icon: string; label: string; active: boolean }> = ({ to, icon, label, active }) => (
  <Link to={to} className={`flex flex-col items-center justify-center gap-1 transition-all duration-300 ${active ? 'text-primary' : 'text-slate-500'}`}>
    <span className={`material-symbols-outlined text-[24px] ${active ? 'filled' : ''}`}>
      {icon}
    </span>
    <span className="text-[9px] font-black uppercase tracking-tight">
      {label}
    </span>
  </Link>
);

export default App;

