  LOYALTY_CAMPAIGNS: 'ecobr232_loyalty_campaigns',
  LOYALTY_WALLET: 'ecobr232_loyalty_wallet'
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const db = {
  ads: {
    async getAll(): Promise<StoredAd[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ADS);
      return data ? JSON.parse(data) : [];
    },
    async save(ad: Omit<StoredAd, 'id' | 'createdAt' | 'rating' | 'isVerified'>): Promise<StoredAd> {
      await delay(300);
      const ads = await this.getAll();
      const newAd: StoredAd = {
        ...ad,
        id: Math.random().toString(36).substr(2, 9),
        createdAt: Date.now(),
        rating: 5.0,
        isVerified: false
      };
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify([newAd, ...ads]));
      return newAd;
    },
    async delete(id: string): Promise<void> {
      const ads = await this.getAll();
      const filtered = ads.filter(a => a.id !== id);
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify(filtered));
    }
  },
  alerts: {
    async getAll(): Promise<StoredAlert[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ALERTS);
      return data ? JSON.parse(data) : [];
    },
    async save(alert: Omit<StoredAlert, 'id' | 'timestamp'>): Promise<StoredAlert> {
      await delay(300);
      const alerts = await this.getAll();
      const newAlert: StoredAlert = {
        ...alert,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      localStorage.setItem(STORAGE_KEYS.ALERTS, JSON.stringify([newAlert, ...alerts]));
      return newAlert;
    }
  },
  loyalty: {
    // Para o Comerciante (Gestão)
    async getMyCampaigns(): Promise<LoyaltyCampaign[]> {
      const data = localStorage.getItem(STORAGE_KEYS.LOYALTY_CAMPAIGNS);
      if (data) return JSON.parse(data);

      // Mock inicial para o usuário ver algo
      const initial: LoyaltyCampaign[] = [
        {
          id: 'camp_demo',
          merchantName: 'Rei das Coxinhas',
          tier: LoyaltyTier.PRO,
          title: 'Clube da Coxinha',
          goal: 10,
          reward: '1 Coxinha com Queijo',
          rules: 'Válido para consumo na loja.',
          color: '#e31d24',
          activeUsers: 142
        }
      ];
      localStorage.setItem(STORAGE_KEYS.LOYALTY_CAMPAIGNS, JSON.stringify(initial));
      return initial;
    },
    async createCampaign(camp: Omit<LoyaltyCampaign, 'id' | 'activeUsers'>): Promise<LoyaltyCampaign> {
      await delay(500);
      const list = await this.getMyCampaigns();
      const newCamp: LoyaltyCampaign = {
        ...camp,
        id: Math.random().toString(36).substr(2, 9),
        activeUsers: 0
      };
      localStorage.setItem(STORAGE_KEYS.LOYALTY_CAMPAIGNS, JSON.stringify([...list, newCamp]));
      return newCamp;
    },
    // Para o Usuário (Carteira)
    async getWallet(): Promise<LoyaltyCard[]> {
      const data = localStorage.getItem(STORAGE_KEYS.LOYALTY_WALLET);
      if (data) return JSON.parse(data);

      const initial: LoyaltyCard[] = [
        {
          id: 'card_1',
          campaignId: 'camp_demo',
          merchantName: 'Rei das Coxinhas',
          title: 'Clube da Coxinha',
          currentStamps: 7,
          goal: 10,
          reward: '1 Coxinha com Queijo',
          color: '#e31d24',
          lastStampDate: Date.now() - 86400000,
          isCompleted: false
        },
        {
          id: 'card_2',
          campaignId: 'camp_demo_2',
          merchantName: 'Hotel Fazenda Gravatá',
          title: 'Day Use Premium',
          currentStamps: 2,
          goal: 5,
          reward: 'Day Use Grátis',
          color: '#00e676',
          lastStampDate: Date.now() - 172800000,
          isCompleted: false
        }
      ];
      localStorage.setItem(STORAGE_KEYS.LOYALTY_WALLET, JSON.stringify(initial));
      return initial;
    },
    async addStamp(cardId: string): Promise<LoyaltyCard> {
      await delay(800); // Simula validação GPS
      const wallet = await this.getWallet();
      const updated = wallet.map(c => {
        if (c.id === cardId && !c.isCompleted) {
          const newStamps = c.currentStamps + 1;
          const isCompleted = newStamps >= c.goal;
          return {
            ...c,
            currentStamps: newStamps,
            isCompleted,
            voucherCode: isCompleted ? `VCH-${Math.random().toString(36).substr(2, 6).toUpperCase()}` : undefined,
            lastStampDate: Date.now()
          };
        }
        return c;
      });
      localStorage.setItem(STORAGE_KEYS.LOYALTY_WALLET, JSON.stringify(updated));
      return updated.find(c => c.id === cardId)!;
    }
