    async getWallet(): Promise<LoyaltyCard[]> {
      const data = localStorage.getItem(STORAGE_KEYS.LOYALTY_WALLET);
      if (data) return JSON.parse(data);

      const initial: LoyaltyCard[] = [
        {
          id: 'card_1',
