import { initializeApp, getApps, getApp } from 'firebase/app';
import { getAuth, GoogleAuthProvider, Auth } from 'firebase/auth';

/**
 * Helper para acessar variáveis de ambiente de forma segura
 * Tenta acessar via import.meta.env (Vite Standard)
 * Fallback para process.env (Vite Define Polyfill)
 */
const getEnv = (key: string): string => {
  try {
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env[key]) {
      // @ts-ignore
      return import.meta.env[key];
    }
  } catch (e) {}

  try {
    // @ts-ignore
    if (typeof process !== 'undefined' && process.env && process.env[key]) {
      // @ts-ignore
      return process.env[key] as string;
    }
  } catch (e) {}

  return '';
};

const firebaseConfig = {
  apiKey: getEnv('VITE_FIREBASE_API_KEY'),
  authDomain: getEnv('VITE_FIREBASE_AUTH_DOMAIN'),
  projectId: getEnv('VITE_FIREBASE_PROJECT_ID'),
  storageBucket: getEnv('VITE_FIREBASE_STORAGE_BUCKET'),
  messagingSenderId: getEnv('VITE_FIREBASE_MESSAGING_SENDER_ID'),
  appId: getEnv('VITE_FIREBASE_APP_ID')
};

let auth: Auth;
let googleProvider: GoogleAuthProvider;

const createMockAuth = () => {
  console.log("🛠️ Rodando Firebase em Modo Mock (Fundação)");
  return {
    currentUser: null,
    signOut: async () => console.log("Mock SignOut"),
    onAuthStateChanged: (cb: any) => { cb(null); return () => {}; },
    // Adicionando propriedades necessárias para evitar crash ao acessar
    app: {},
    name: 'mock-auth',
    config: {},
    beforeAuthStateChanged: () => {},
    onIdTokenChanged: () => () => {},
    setPersistence: async () => {},
    tenantId: null,
    settings: { appVerificationDisabledForTesting: true },
    languageCode: 'pt'
  } as unknown as Auth;
};

// Se não houver API Key válida, usa Mock imediatamente
if (!firebaseConfig.apiKey || firebaseConfig.apiKey.length < 5) {
  auth = createMockAuth();
  googleProvider = new GoogleAuthProvider(); // Instancia vazia não faz mal
} else {
  try {
    const app = !getApps().length ? initializeApp(firebaseConfig) : getApp();
    auth = getAuth(app);
    auth.languageCode = 'pt';
    googleProvider = new GoogleAuthProvider();
  } catch (error) {
    console.warn("⚠️ Falha ao conectar Firebase Real. Revertendo para Mock.", error);
    auth = createMockAuth();
    googleProvider = new GoogleAuthProvider();
  }
}

export { auth, googleProvider };

