];

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// Implementação Atual: LOCAL (Single Player)
// TODO: Criar 'FirestoreRepository' para Beta Multiplayer
export const db = {
  ads: {
    async getAll(): Promise<StoredAd[]> {
      const data = safeStorage.getItem(STORAGE_KEYS.ADS);
      return data ? JSON.parse(data) : [];
    },
    async save(ad: Omit<StoredAd, 'id' | 'createdAt' | 'rating' | 'isVerified'>): Promise<StoredAd> {
      await delay(300); // Simula latência de rede
