          id: 'card_2',
          campaignId: 'camp_demo_2',
          merchantName: 'Hotel Fazenda Gravatá',
          title: 'Day Use Premium',
          currentStamps: 2,
          goal: 5,
          reward: 'Day Use Grátis',
          color: '#00e676',
          lastStampDate: Date.now() - 172800000,
          isCompleted: false
        }
      ];
      safeStorage.setItem(STORAGE_KEYS.LOYALTY_WALLET, JSON.stringify(initial));
      return initial;
    },
    async addStamp(cardId: string): Promise<LoyaltyCard> {
      await delay(800);
      const wallet = await this.getWallet();
      const updated = wallet.map(c => {
        if (c.id === cardId && !c.isCompleted) {
          const newStamps = c.currentStamps + 1;
          const isCompleted = newStamps >= c.goal;
          return {
            ...c,
            currentStamps: newStamps,
            isCompleted,
            voucherCode: isCompleted ? `VCH-${Math.random().toString(36).substr(2, 6).toUpperCase()}` : undefined,
            lastStampDate: Date.now()
          };
        }
        return c;
      });
      safeStorage.setItem(STORAGE_KEYS.LOYALTY_WALLET, JSON.stringify(updated));
      return updated.find(c => c.id === cardId)!;
    }
  },
  mneme: {
    async getLists(): Promise<MnemeList[]> {
      const data = safeStorage.getItem(STORAGE_KEYS.MNEME_LISTS);
      if (data) return JSON.parse(data);
      const initial: MnemeList[] = [
        {
          id: 'list_1',
          title: 'Compras do Mês',
          createdAt: Date.now(),
          status: 'active',
          items: [
            { id: '1', name: 'Leite Integral', category: 'Mercearia', quantity: 12, unit: 'un', checked: false, estimatedPrice: 72.00 },
            { id: '2', name: 'Café (500g)', category: 'Mercearia', quantity: 2, unit: 'pct', checked: true, estimatedPrice: 35.00 }
          ],
          totalEstimated: 107.00
        }
      ];
      safeStorage.setItem(STORAGE_KEYS.MNEME_LISTS, JSON.stringify(initial));
      return initial;
    },
    async createList(title: string, items: MnemeItem[] = []): Promise<MnemeList> {
      const lists = await this.getLists();
      const newList: MnemeList = {
        id: Math.random().toString(36).substr(2, 9),
        title,
        createdAt: Date.now(),
        status: 'active',
        items,
        totalEstimated: items.reduce((acc, i) => acc + (i.estimatedPrice || 0), 0)
      };
      safeStorage.setItem(STORAGE_KEYS.MNEME_LISTS, JSON.stringify([newList, ...lists]));
      return newList;
    },
    async updateList(list: MnemeList): Promise<void> {
      const lists = await this.getLists();
      const updated = lists.map(l => l.id === list.id ? list : l);
      safeStorage.setItem(STORAGE_KEYS.MNEME_LISTS, JSON.stringify(updated));
    },
    async getProductByBarcode(ean: string): Promise<ProductMock | undefined> {
      await delay(500); // Simulate scan processing
      return OFFLINE_PRODUCTS_DB.find(p => p.ean === ean) || OFFLINE_PRODUCTS_DB[Math.floor(Math.random() * OFFLINE_PRODUCTS_DB.length)]; // Fallback random para teste
    }
  },
  referrals: {
    async getStats(): Promise<ReferralStats> {
      const data = safeStorage.getItem(STORAGE_KEYS.USER_STATS);
      if (data) return JSON.parse(data);

      const defaultStats: ReferralStats = {
        referralCode: 'ADM-232',
        totalReferrals: 0,
        pendingCredits: 0,
        adCredits: 0,
        commissionRate: 0.10,
        campaignStart: Date.now(),
        campaignDurationDays: 30,
        benefitExpiryMonths: 24
      };
      safeStorage.setItem(STORAGE_KEYS.USER_STATS, JSON.stringify(defaultStats));
      return defaultStats;
    },
    async simulateTimeProgress(days: number): Promise<void> {
      const stats = await this.getStats();
      const newStart = stats.campaignStart - (days * 24 * 60 * 60 * 1000);
      safeStorage.setItem(STORAGE_KEYS.USER_STATS, JSON.stringify({
        ...stats,
        campaignStart: newStart
      }));
    }
  },
  system: {
    async resetAll(): Promise<void> {
      safeStorage.clear();
    }
  }
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RotateCcw, Home } from 'lucide-react';

interface Props {
  children?: ReactNode;
  moduleName?: string;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * Módulo de Segurança (Shielding)
 * Impede que falhas em sub-módulos derrubem a aplicação inteira.
 * Implementação Robusta (Class Component).
 */
class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`[CRITICAL] Falha no módulo ${this.props.moduleName}:`, error, errorInfo);
  }

  public handleRetry = () => {
    this.setState({ hasError: false, error: null });
    window.location.reload();
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] p-8 text-center bg-background-dark/50 rounded-[2rem] border border-red-500/20 m-4">
          <div className="size-16 bg-red-500/10 rounded-2xl flex items-center justify-center mb-6 border border-red-500/20 animate-pulse">
            <AlertTriangle size={32} className="text-red-500" />
          </div>

          <h2 className="text-xl font-black italic uppercase text-white mb-2">
            Módulo Indisponível
          </h2>

          <p className="text-sm text-slate-400 font-medium max-w-xs mx-auto mb-8 leading-relaxed">
            Ocorreu uma instabilidade na área <span className="text-primary font-bold">{this.props.moduleName || 'Sistema'}</span>. 
            A operação foi isolada para proteger o restante da malha.
          </p>

          <div className="flex gap-4">
            <button 
              onClick={() => window.location.href = '#/dashboard'}
              className="px-6 py-3 bg-white/5 rounded-xl text-xs font-black uppercase text-white border border-white/10 hover:bg-white/10 flex items-center gap-2"
            >
              <Home size={14} /> Início
            </button>
            <button 
              onClick={this.handleRetry}
              className="px-6 py-3 bg-primary text-black rounded-xl text-xs font-black uppercase border border-primary hover:brightness-110 flex items-center gap-2"
            >
              <RotateCcw size={14} /> Reconectar
            </button>
          </div>

          <div className="mt-8 pt-8 border-t border-white/5 w-full">
            <p className="text-[9px] font-mono text-slate-600 uppercase">
              ERR_CODE: {this.state.error?.name || 'UNKNOWN'}
            </p>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

